mapper.select:
SELECT ROWNUM AS ROW_NUM, PWFR.PA_WORK_FLOW_RECORDS_NO, PWFR.PA_WORK_FLOW_NO, PWFR.FLOW_STEP, TO_CHAR(PWFR.CREATE_DATE, 'DD/MM/YYYY HH24:MI') AS CREATE_DATE, GET_EMP_LOCAL_NAME(PWFR.CREATED_BY, #{cpnyId, jdbcType=VARCHAR})||' '||PWFR.CREATED_IP AS CREATED_BY, PWFR.CREATED_IP FROM PA_WORK_FLOW_RECORDS PWFR JOIN PA_WORK_FLOW PWF ON PWFR.PA_WORK_FLOW_NO = PWF.PA_WORK_FLOW_NO JOIN PA_PAY_SCHEDULE PPS ON PWF.PAY_SCHEDULE_NO = PPS.PAY_SCHEDULE_NO WHERE PPS.PAY_SCHEDULE_NO = #{payScheduleNo, jdbcType=VARCHAR} AND PPS.CPNY_ID = #{cpnyId, jdbcType=VARCHAR}
AND PWFR.FLOW_STEP = #{flowStep, jdbcType=NUMERIC}
ORDER BY PWFR.PA_WORK_FLOW_RECORDS_NO ASC

{CALL PKG_PA_WORK_FLOW.PA_WORKFLOW_EXECUTE(
    #{payScheduleNo, jdbcType=VARCHAR, mode=IN},
    #{adminID,       jdbcType=VARCHAR, mode=IN},
    #{adminIP,       jdbcType=VARCHAR, mode=IN},
    #{cpnyId,        jdbcType=VARCHAR, mode=IN},
    #{type,          jdbcType=VARCHAR, mode=IN},
    #{message,       jdbcType=VARCHAR, mode=OUT}
)}
